class Solution {
public:
    string arrangeWords(string text) {
        vector<string> words;
        string word = "";
        for (char c : text) {
            if (c == ' ') {
                words.push_back(word);
                word = "";
            } else {
                word += c;
            }
        }
        words.push_back(word);

        stable_sort(words.begin(), words.end(), [](const string& a, const string& b) {
            return a.size() < b.size();
        });

        string result = "";
        for (int i = 0; i < words.size(); i++) {
            if (i == 0) {
                words[i][0] = toupper(words[i][0]);
            } else {
                for (char& c : words[i]) {
                    c = tolower(c);
                }
            }
            result += words[i];
            if (i < words.size() - 1) {
                result += " ";
            }
        }
        return result;
    }
};

